  ('judicial-d35ec6db-moex-00373', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-d1a761c9', 'sub-judicial-d35ec6db-05', NULL, 'single_choice', '關於聽證之敘述，下列何者錯誤？', '["聽證以不公開為原則，不開放旁聽", "行政機關得於聽證期日前舉行預備聽證", "聽證主持人得由行政機關首長指定之", "行政機關未經當事人之申請，亦得變更聽證期日"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:14+00:00", "source_pdf_sha1": "5ef74afcdd2c", "answer_pdf_sha1": "e5ded5215165", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
  ('judicial-d35ec6db-moex-00374', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-d1a761c9', 'sub-judicial-d35ec6db-05', NULL, 'single_choice', '下列應限制公開之政府資訊，何者基於公益之必要仍得公開？', '["公開足以妨害刑事被告受公正之裁判者", "政府機關為實施監督業務，而取得監督對象之相關資料，其公開將對實施目的造成困難或妨害者", "為保存文化資產必須特別管理，而公開有滅失或減損其價值之虞者", "公開有侵害個人隱私、職業上秘密或著作權人之公開發表權者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:14+00:00", "source_pdf_sha1": "5ef74afcdd2c", "answer_pdf_sha1": "e5ded5215165", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL),
