  ('judicial-d35ec6db-moex-00376', 'judicial-d35ec6db', 'judicial-d35ec6db-moex-111-d1a761c9', 'sub-judicial-d35ec6db-05', NULL, 'single_choice', '若對於當事人之送達，因應為送達之處所不明，以黏貼於行政機關公告欄、但未同時刊登政府公報或新聞 紙之方式對應受送達人為公示送達。關於此送達之效力，下列敘述何者正確？', '["因未送達於當事人本人，不發生送達之效果", "自公告之翌日起生效", "自公告之日起，經20日發生效力", "自公告黏貼於公告欄最後之日起，經30日發生效力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:14+00:00", "source_pdf_sha1": "5ef74afcdd2c", "answer_pdf_sha1": "e5ded5215165", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "205", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執行員"}'::jsonb, NULL)
